// TriStateCheckbox.native.tsx
import React, { useCallback, useMemo } from "react";
import { Pressable } from "react-native";
import { Check, Minus } from "lucide-react-native";
import type { TriStateCheckboxProps } from "./TriStateCheckbox.types";
export * from './TriStateCheckbox.types';

export const TriStateCheckbox: React.FC<TriStateCheckboxProps> = ({
                                                                    value = null,
                                                                    disabled = false,
                                                                    readOnly = false,
                                                                    invalid = false,
                                                                    variant = "outlined",
                                                                    unstyled = false,
                                                                    checkIcon: CheckIcon = Check,
                                                                    uncheckIcon: UncheckIcon = Minus,
                                                                    onChange,
                                                                    children,
                                                                  }) => {
  // 🔒 deterministic state cycle
  const nextValue = useCallback((current: boolean | null) => {
    if (current === null) return true;
    if (current === true) return false;
    return null;
  }, []);

  const handlePress = useCallback(() => {
    if (disabled || readOnly) return;

    const newValue = nextValue(value);

    onChange?.({
      value: newValue,
      checked: newValue === true,
    });
  }, [disabled, readOnly, value, nextValue, onChange]);

  const Icon = useMemo(() => {
    if (value === true) return CheckIcon;
    if (value === null) return UncheckIcon;
    return null;
  }, [value, CheckIcon, UncheckIcon]);

  if (unstyled) {
    return (
      <Pressable onPress={handlePress} disabled={disabled}>
        {Icon && <Icon />}
        {children}
      </Pressable>
    );
  }

  return (
    <Pressable
      onPress={handlePress}
      disabled={disabled}
      accessibilityRole="checkbox"
      accessibilityState={{
        disabled,
        checked: value === true ? true : value === false ? false : "mixed",
      }}
      className={[
        "w-5 h-5 items-center justify-center rounded",
        variant === "outlined"
          ? "border border-gray-400"
          : "bg-gray-200",
        invalid && "border-red-500",
        disabled && "opacity-50",
      ].join(" ")}
    >
      {Icon && <Icon size={14} />}
      {children}
    </Pressable>
  );
};
